<div class="min-vh-100 d-flex align-items-center justify-content-center bg-primary bg-gradient">
  <div class="card shadow-lg border-0" style="width:420px; border-radius:16px;">
    <div class="card-body p-5">
      <div class="text-center mb-4">
        <div class="bg-primary text-white rounded-circle d-inline-flex align-items-center justify-content-center mb-3" style="width:64px;height:64px;">
          <i class="bi bi-mortarboard-fill fs-3"></i>
        </div>
        <h3 class="fw-bold text-primary mb-1">Student MS</h3>
        <p class="text-muted small">Sign in to your account</p>
      </div>

      <div class="alert alert-danger small py-2" *ngIf="error">{{ error }}</div>

      <form [formGroup]="form" (ngSubmit)="submit()">
        <div class="mb-3">
          <label class="form-label fw-semibold">Email address</label>
          <div class="input-group">
            <span class="input-group-text bg-light border-end-0"><i class="bi bi-envelope"></i></span>
            <input type="email" class="form-control border-start-0" formControlName="email" placeholder="admin@sms.com">
          </div>
        </div>
        <div class="mb-4">
          <label class="form-label fw-semibold">Password</label>
          <div class="input-group">
            <span class="input-group-text bg-light border-end-0"><i class="bi bi-lock"></i></span>
            <input type="password" class="form-control border-start-0" formControlName="password" placeholder="••••••••">
          </div>
        </div>
        <button class="btn btn-primary w-100 py-2 fw-semibold" type="submit" [disabled]="loading">
          <span *ngIf="loading" class="spinner-border spinner-border-sm me-2"></span>
          {{ loading ? 'Signing in...' : 'Sign In' }}
        </button>
      </form>

